INSERT INTO _import_item_data (name, description, cost_gp, weight_lb, is_magical) VALUES
    ('Acid', 'When you take the Attack action, you can replace one of your attacks with throwing a vial of Acid. Target one creature or object you can see within 20 feet of yourself. The target must succeed on a Dexterity saving throw (DC 8 plus your Dexterity modifier and Proficiency Bonus) or take 2d6 Acid damage.', 25.00, 1.00, FALSE),
    ('Airship', 'A ship sailing against a strong wind moves at half speed. In a dead calm (no wind), waterborne ships can''t move under sail and must be rowed. Keelboats and Rowboats are used on lakes and rivers. If going downstream, add the speed of the current (typically 3 miles per hour) to the speed of the vehicle. These vehicles can''t be rowed against any significant current, but they can be pulled upstream by draft animals on the shores. A Rowboat can be carried and weighs 100 pounds. A ship larger than a Keelboat or Rowboat needs a crew of skilled hirelings (see "Services") to function. The minimum nu...', 40.00, NULL, FALSE),
    ('Alchemist''s Fire', 'When you take the Attack action, you can replace one of your attacks with throwing a flask of Alchemist''s Fire. Target one creature or object you can see within 20 feet of yourself. The target must succeed on a Dexterity saving throw (DC 8 plus your Dexterity modifier and Proficiency Bonus) or take 1d4 Fire damage and start burning.', 50.00, 1.00, FALSE),
    ('Ale (mug)', 'Food and Drink', NULL, NULL, FALSE),
    ('Amulet', 'For an Amulet to be an effective Holy Symbol, it must be worn or held. A cleric or paladin can use this item as a spellcasting focus.', 5.00, 1.00, FALSE),
    ('Antitoxin', 'As a Bonus Action, you can drink a vial of Antitoxin to gain Advantage on saving throws to avoid or end the Poisoned condition for 1 hour.', 50.00, NULL, FALSE),
    ('Arcane Focus', 'A sorcerer, warlock, or wizard can use this item as a spellcasting focus.', NULL, NULL, FALSE),
    ('Arrow', 'Arrows are used with a weapon that has the ammunition property to make a ranged attack. Each time you attack with the weapon, you expend one piece of ammunition. Drawing the ammunition from a quiver, case, or other container is part of the attack (you need a free hand to load a one-handed weapon). At the end of the battle, you can recover half your expended ammunition by taking a minute to search the battlefield. Arrows are typically stored in a Quiver (bought separately).', NULL, 0.80, FALSE),
    ('Arrows (20)', 'Arrows are used with a weapon that has the ammunition property to make a ranged attack. Each time you attack with the weapon, you expend one piece of ammunition. Drawing the ammunition from a quiver, case, or other container is part of the attack (you need a free hand to load a one-handed weapon). At the end of the battle, you can recover half your expended ammunition by taking a minute to search the battlefield. Arrows are typically stored in a Quiver (bought separately).', 1.00, 1.00, FALSE),
    ('Artisan''s Tools', 'Artisan''s Tools are each focused on crafting items and pursuing a trade. Each type of Artisan''s Tools tools requires a separate proficiency. If you have proficiency with a tool, add your Proficiency Bonus to any ability check you make that uses the tool. If you have proficiency in a skill that''s used with that check, you have Advantage on the check too.', NULL, NULL, FALSE),
    ('Assassin''s Blood', 'A creature subjected to Assassin''s Blood makes a DC 10 Constitution saving throw. On a failed save, the creature takes 6 (1d12) Poison damage and has the Poisoned condition for 24 hours. On a successful save, the creature takes half as much damage only.', 150.00, NULL, FALSE),
    ('Backpack', 'A Backpack holds up to 30 pounds within 1 cubic foot. It can also serve as a saddlebag.', 2.00, 5.00, FALSE),
    ('Ball Bearings', 'As a Utilize action, you can spill Ball Bearings from their pouch. They spread to cover a level, 10-foot-square area within 10 feet of yourself. A creature that enters this area for the first time on a turn must succeed on a DC 10 Dexterity saving throw or have the Prone condition. It takes 10 minutes to recover the Ball Bearings.', 1.00, 2.00, FALSE),
    ('Barrel', 'A Barrel holds up to 40 gallons of liquid or up to 4 cubic feet of dry goods.', 2.00, 70.00, FALSE),
    ('Basic Poison', 'As a Bonus Action, you can use a vial of Basic Poison to coat one weapon or up to three pieces of ammunition. A creature that takes Piercing or Slashing damage from the poisoned weapon or ammunition takes an extra 1d4 Poison damage. Once applied, the poison retains potency for 1 minute or until its damage is dealt, whichever comes first.', 100.00, NULL, FALSE),
    ('Basket', 'A Basket holds up to 40 pounds within 2 cubic feet.', NULL, 2.00, FALSE),
    ('Bedroll', 'A Bedroll sleeps one Small or Medium creature. While in a Bedroll, you automatically succeed on saving throws against extreme cold (see the Dungeon Master''s Guide).', 1.00, 7.00, FALSE),
    ('Bell', 'When rung as a Utilize action, a Bell produces a sound that can be heard up to 60 feet away.', 1.00, NULL, FALSE),
    ('Blanket', 'While wrapped in a blanket, you have Advantage on saving throws against extreme cold (see the Dungeon Master''s Guide).', NULL, 3.00, FALSE),
    ('Block and Tackle', 'A Block and Tackle allows you to hoist up to four times the weight you can normally lift.', 1.00, 5.00, FALSE),
    ('Bolt', 'Crossbow bolts are used with a weapon that has the ammunition property to make a ranged attack. Each time you attack with the weapon, you expend one piece of ammunition. Drawing the ammunition from a quiver, case, or other container is part of the attack (you need a free hand to load a one-handed weapon). At the end of the battle, you can recover half your expended ammunition by taking a minute to search the battlefield. Bolts are typically stored in a Crossbow Bolt Case (bought separately).', NULL, 1.20, FALSE),
    ('Bolts (20)', 'Crossbow bolts are used with a weapon that has the ammunition property to make a ranged attack. Each time you attack with the weapon, you expend one piece of ammunition. Drawing the ammunition from a quiver, case, or other container is part of the attack (you need a free hand to load a one-handed weapon). At the end of the battle, you can recover half your expended ammunition by taking a minute to search the battlefield. Bolts are typically stored in a Crossbow Bolt Case (bought separately).', 1.00, 1.00, FALSE),
    ('Bomb', 'As an action, you can light a Bomb and throw it at a point up to 60 feet away, where it explodes. Each creature in a 5-foot-radius Sphere centered on that point makes a DC 12 Dexterity saving throw, taking 3d6 Fire damage on a failed save or half as much damage on a successful one.', 100.00, 1.00, FALSE),
    ('Book', 'A Book contains fiction or nonfiction. If you consult an accurate nonfiction Book about its topic, you gain a +5 bonus to Intelligence (Arcana, History, Nature, or Religion) checks you make about that topic.', 25.00, 5.00, FALSE),
    ('Bread (loaf)', 'Food and Drink', NULL, NULL, FALSE),
    ('Bucket', 'A Bucket holds up to half a cubic foot of contents.', NULL, 2.00, FALSE),
    ('Bullseye Lantern', 'A Bullseye Lantern burns Oil as fuel to cast Bright Light in a 60-foot Cone and Dim Light for an additional 60 feet.', 10.00, 2.00, FALSE),
    ('Burglar''s Pack', 'A Burglar''s Pack contains the following items: Backpack, Ball Bearings, Bell, 10 Candles, Crowbar, Hooded Lantern, 7 flasks of Oil, 5 days of Rations, Rope, Tinderbox, and Waterskin.', 16.00, 47.00, FALSE),
    ('Burnt Othur Fumes', 'A creature subjected to Burnt Othur Fumes must succeed on a DC 13 Constitution saving throw or take 10 (3d6) Poison damage, and it must repeat the save at the start of each of its turns. On each successive failed save, the creature takes 3 (1d6) Poison damage. After three successful saves, the poison ends.', 500.00, NULL, FALSE),
    ('Caltrops', 'As a Utilize action, you can spread Caltrops from their bag to cover a 5-foot-square area within 5 feet of yourself. A creature that enters this area for the first time on a turn must succeed on a DC 15 Dexterity saving throw or take 1 Piercing damage and have its Speed reduced to 0 until the start of its next turn. It takes 10 minutes to recover the Caltrops.', 1.00, 2.00, FALSE),
    ('Camel', 'Mount', 50.00, NULL, FALSE),
    ('Candle', 'For 1 hour, a lit Candle sheds Bright Light in a 5-foot radius and Dim Light for an additional 5 feet.', NULL, NULL, FALSE),
    ('Canvas (1 sq. yd.)', 'Merchants commonly exchange trade goods without using currency.', NULL, NULL, FALSE),
    ('Carriage', 'Vehicle (Land)', 100.00, 600.00, FALSE),
    ('Carrion Crawler Mucus', 'A creature subjected to Carrion Crawler Mucus must succeed on a DC 13 Constitution saving throw or have the Poisoned condition for 1 minute. The creature also has the Paralyzed condition while Poisoned in this way. The creature repeats the save at the end of each of its turns, ending the effect on itself on a success.', 200.00, NULL, FALSE),
    ('Cart', 'Vehicle (Land)', 15.00, 200.00, FALSE),
    ('Chain', 'As a Utilize action, you can wrap a Chain around an unwilling creature within 5 feet of yourself that has the Grappled, Incapacitated, or Restrained condition if you succeed on a DC 13 Strength (Athletics) check. If the creature''s legs are bound, the creature has the Restrained condition until it escapes. Escaping the Chain requires the creature to make a successful DC 18 Dexterity (Acrobatics) check as an action. Bursting the Chain requires a successful DC 20 Strength (Athletics) check as an action.', 5.00, 10.00, FALSE),
    ('Chariot', 'Vehicle (Land)', 250.00, 100.00, FALSE),
    ('Cheese (wedge)', 'Food and Drink', NULL, NULL, FALSE),
    ('Chest', 'A Chest holds up to 12 cubic feet of contents.', 5.00, 25.00, FALSE),
    ('Chicken', 'Merchants commonly exchange trade goods without using currency.', NULL, NULL, FALSE),
    ('Cinnamon', 'Merchants commonly exchange trade goods without using currency.', 2.00, 1.00, FALSE),
    ('Climber''s Kit', 'A Climber''s Kit includes boot tips, gloves, pitons, and a harness. As a Utilize action, you can use the Climber''s Kit to anchor yourself; when you do, you can''t fall more than 25 feet from the anchor point, and you can''t move more than 25 feet from there without undoing the anchor as a Bonus Action.', 25.00, 12.00, FALSE),
    ('Cloves', 'Merchants commonly exchange trade goods without using currency.', 3.00, 1.00, FALSE),
    ('Common Wine (bottle)', 'Food and Drink', NULL, NULL, FALSE),
    ('Component Pouch', 'A Component Pouch is watertight and filled with compartments that hold all the free Material components of your spells.', 25.00, 2.00, FALSE),
    ('Copper', 'Merchants commonly exchange trade goods without using currency.', NULL, 1.00, FALSE),
    ('Costume', 'While wearing a Costume, you have Advantage on any ability check you make to impersonate the person or type of person it represents.', 5.00, 4.00, FALSE),
    ('Cotton Cloth (1 sq. yd.)', 'Merchants commonly exchange trade goods without using currency.', NULL, NULL, FALSE),
    ('Cow', 'Merchants commonly exchange trade goods without using currency.', 10.00, NULL, FALSE),
    ('Crossbow Bolt Case', 'A Crossbow Bolt Case holds up to 20 Bolts.', 1.00, 1.00, FALSE),
    ('Crowbar', 'Using a Crowbar gives you Advantage on Strength checks where the Crowbar''s leverage can be applied.', 2.00, 5.00, FALSE),
    ('Crystal', 'A sorcerer, warlock, or wizard can use this item as a spellcasting focus.', 10.00, 1.00, FALSE),
    ('Diplomat''s Pack', 'A Diplomat''s Pack contains the following items: Chest, Fine Clothes, Ink, 5 Ink Pens, Lamp, 2 Map or Scroll Cases, 4 flasks of Oil, 5 sheets of Paper, 5 sheets of Parchment, Perfume, and Tinderbox.', 39.00, 39.00, FALSE),
    ('Draft Horse', 'Mount', 50.00, NULL, FALSE),
    ('Druidic Focus', 'A druid can use this item as a spellcasting focus.', NULL, NULL, FALSE),
    ('Dungeoneer''s Pack', 'A Dungeoneer''s Pack contains the following items: Backpack, Caltrops, Crowbar, 2 flasks of Oil, 10 days of Rations, Rope, Tinderbox, 10 Torches, and Waterskin.', 12.00, 55.00, FALSE),
    ('Elephant', 'Mount', 200.00, NULL, FALSE),
    ('Emblem', 'For an Emblem to be an effective Holy Symbol, it must be borne on fabric (such as a tabard or banner) or a Shield. A cleric or paladin can use this item as a spellcasting focus.', 5.00, NULL, FALSE),
    ('Entertainer''s Pack', 'An Entertainer''s Pack contains the following items: Backpack, Bedroll, Bell, Bullseye Lantern, 3 Costumes, Mirror, 8 flasks of Oil, 9 days of Rations, Tinderbox, and Waterskin.', 40.00, 58.00, FALSE),
    ('Essence of Ether', 'A creature subjected to Essence of Ether must succeed on a DC 15 Constitution saving throw or have the Poisoned condition for 8 hours. The creature also has the Unconscious condition while Poisoned in this way. The creature wakes up if it takes damage or if another creature takes an action to shake it awake.', 300.00, NULL, FALSE),
    ('Exotic Saddle', 'A saddle comes with a bit, a bridle, reins, and any other equipment needed to use the saddle. An Exotic Saddle is required for riding an aquatic or a flying mount.', 60.00, 40.00, FALSE),
    ('Explorer''s Pack', 'An Explorer''s Pack contains the following items: Backpack, Bedroll, 2 flasks of Oil, 10 days of Rations, Rope, Tinderbox, 10 Torches, and Waterskin.', 10.00, 55.00, FALSE),
    ('Feed (per day)', 'Tack and Harness', NULL, 10.00, FALSE),
    ('Fine Clothes', 'Fine Clothes are made of expensive fabrics and adorned with expertly crafted details. Some events and locations admit only people wearing these clothes.', 15.00, 6.00, FALSE),
    ('Fine Wine (bottle)', 'Food and Drink', 10.00, NULL, FALSE),
    ('Firearm Bullet', 'Firearm Bullets are destroyed upon use in a modern firearm.', NULL, NULL, FALSE),
    ('Firearm Bullets (10)', 'Firearm Bullets are destroyed upon use in a modern firearm.', 3.00, 2.00, FALSE),
    ('Flask', 'A Flask holds up to 1 pint.', NULL, 1.00, FALSE),
    ('Flour', 'Merchants commonly exchange trade goods without using currency.', NULL, 2.00, FALSE),
    ('Galley', 'A ship sailing against a strong wind moves at half speed. In a dead calm (no wind), waterborne ships can''t move under sail and must be rowed. Keelboats and Rowboats are used on lakes and rivers. If going downstream, add the speed of the current (typically 3 miles per hour) to the speed of the vehicle. These vehicles can''t be rowed against any significant current, but they can be pulled upstream by draft animals on the shores. A Rowboat can be carried and weighs 100 pounds. A ship larger than a Keelboat or Rowboat needs a crew of skilled hirelings (see "Services") to function. The minimum nu...', 30.00, NULL, FALSE),
    ('Gaming Set', 'If you have proficiency with a tool, add your Proficiency Bonus to any ability check you make that uses the tool. If you have proficiency in a skill that''s used with that check, you have Advantage on the check too.', NULL, NULL, FALSE),
    ('Ginger', 'Merchants commonly exchange trade goods without using currency.', 1.00, 1.00, FALSE),
    ('Glass Bottle', 'A Glass Bottle holds up to 1½ pints.', 2.00, 2.00, FALSE),
    ('Goat', 'Merchants commonly exchange trade goods without using currency.', 1.00, NULL, FALSE),
    ('Gold', 'Merchants commonly exchange trade goods without using currency.', 50.00, 1.00, FALSE),
    ('Grappling Hook', 'As a Utilize action, you can throw the Grappling Hook at a railing, a ledge, or another catch within 50 feet of yourself, and the hook catches on if you succeed on a DC 13 Dexterity (Acrobatics) check. If you tied a Rope to the hook, you can then climb it.', 2.00, 4.00, FALSE),
    ('Gunpowder (keg)', 'Setting fire to a keg full of Gunpowder causes it to explode. When a keg explodes, each creature in a 10-foot-radius Sphere centered on the keg makes a DC 12 Dexterity saving throw, taking 24 (7d6) Fire damage on a failed save or half as much damage on a successful one.', 250.00, 20.00, FALSE),
    ('Gunpowder (powder horn)', 'Setting fire to a powder horn full of Gunpowder causes it to explode. When a powder horn explodes, each creature in a 10-foot-radius Sphere centered on the powder horn makes a DC 12 Dexterity saving throw, taking 10 (3d6) Fire damage on a failed save or half as much damage on a successful one.', 35.00, 2.00, FALSE),
    ('Healer''s Kit', 'A Healer''s Kit has ten uses. As a Utilize action, you can expend one of its uses to stabilize an Unconscious creature that has 0 Hit Points without needing to make a Wisdom (Medicine) check.', 5.00, 3.00, FALSE),
    ('Holy Symbol', 'A cleric or paladin can use this item as a spellcasting focus.', NULL, NULL, FALSE),
    ('Holy Water', 'When you take the Attack action, you can replace one of your attacks with throwing a flask of Holy Water. Target one creature you can see within 20 feet of yourself. The target must succeed on a Dexterity saving throw (DC 8 plus your Dexterity modifier and Proficiency Bonus) or take 2d8 Radiant damage if it is a Fiend or an Undead.', 25.00, 1.00, FALSE),
    ('Hooded Lantern', 'A Hooded Lantern burns Oil as fuel to cast Bright Light in a 30-foot radius and Dim Light for an additional 30 feet. As a Bonus Action, you can lower the hood, reducing the light to Dim Light in a 5-foot radius, or raise it again.', 5.00, 2.00, FALSE),
    ('Hunting Trap', 'As a Utilize action, you can set a Hunting Trap, which is a sawtooth steel ring that snaps shut when a creature steps on a pressure plate in the center. The trap is affixed by a heavy chain to an immobile object, such as a tree or a spike driven into the ground. A creature that steps on the plate must succeed on a DC 13 Dexterity saving throw or take 1d4 Piercing damage and have its Speed reduced to 0 until the start of its next turn. Thereafter, until the creature breaks free of the trap, its movement is limited by the length of the chain (typically 3 feet). A creature can use its action t...', 5.00, 25.00, FALSE),
    ('Ink', 'Ink comes in a 1-ounce bottle, which provides enough ink to write about 500 pages.', 10.00, NULL, FALSE),
    ('Ink Pen', 'Using Ink, an Ink Pen is used to write or draw.', NULL, NULL, FALSE),
    ('Iron', 'Merchants commonly exchange trade goods without using currency.', NULL, 1.00, FALSE),
    ('Iron Pot', 'An Iron Pot holds up to 1 gallon.', 2.00, 10.00, FALSE),
    ('Iron Spike', 'Iron Spikes come in bundles of ten. As a Utilize action, you can use a blunt object, such as a Light Hammer, to hammer a spike into wood, earth, or a similar material. You can do so to jam a door shut or to then tie a Rope or Chain to the Spike.', NULL, NULL, FALSE),
    ('Iron Spikes', 'Iron Spikes come in bundles of ten. As a Utilize action, you can use a blunt object, such as a Light Hammer, to hammer a spike into wood, earth, or a similar material. You can do so to jam a door shut or to then tie a Rope or Chain to the Spike.', 1.00, 5.00, FALSE),
    ('Jug', 'A Jug holds up to 1 gallon.', NULL, 4.00, FALSE),
    ('Keelboat', 'A ship sailing against a strong wind moves at half speed. In a dead calm (no wind), waterborne ships can''t move under sail and must be rowed. Keelboats and Rowboats are used on lakes and rivers. If going downstream, add the speed of the current (typically 3 miles per hour) to the speed of the vehicle. These vehicles can''t be rowed against any significant current, but they can be pulled upstream by draft animals on the shores. A Rowboat can be carried and weighs 100 pounds. A ship larger than a Keelboat or Rowboat needs a crew of skilled hirelings (see "Services") to function. The minimum nu...', 3.00, NULL, FALSE),
    ('Ladder', 'A Ladder is 10 feet tall. You must climb to move up or down it.', NULL, 25.00, FALSE),
    ('Lamp', 'A Lamp burns Oil as fuel to cast Bright Light in a 15-foot radius and Dim Light for an additional 30 feet.', NULL, 1.00, FALSE),
    ('Linen (1 sq. yd.)', 'Merchants commonly exchange trade goods without using currency.', 5.00, NULL, FALSE),
    ('Lock', 'A Lock comes with a key. Without the key, a creature can use Thieves'' Tools to pick this Lock with a successful DC 15 Dexterity (Sleight of Hand) check.', 10.00, 1.00, FALSE),
    ('Lolth''s Sting', 'A creature subjected to Lolth''s Sting must succeed on a DC 13 Constitution saving throw or have the Poisoned condition for 1 hour. If the creature fails the save by 5 or more, the creature also has the Unconscious condition while Poisoned in this way. The creature wakes up if it takes damage or if another creature takes an action to shake it awake.', 200.00, NULL, FALSE),
    ('Longship', 'A ship sailing against a strong wind moves at half speed. In a dead calm (no wind), waterborne ships can''t move under sail and must be rowed. Keelboats and Rowboats are used on lakes and rivers. If going downstream, add the speed of the current (typically 3 miles per hour) to the speed of the vehicle. These vehicles can''t be rowed against any significant current, but they can be pulled upstream by draft animals on the shores. A Rowboat can be carried and weighs 100 pounds. A ship larger than a Keelboat or Rowboat needs a crew of skilled hirelings (see "Services") to function. The minimum nu...', 10.00, NULL, FALSE),
    ('Magnifying Glass', 'A Magnifying Glass grants Advantage on any ability check made to appraise or inspect a highly detailed item. Lighting a fire with a Magnifying Glass requires light as bright as sunlight to focus, tinder to ignite, and about 5 minutes for the fire to ignite.', 100.00, NULL, FALSE),
    ('Malice', 'A creature subjected to Malice must succeed on a DC 15 Constitution saving throw or have the Poisoned condition for 1 hour. The creature also has the Blinded condition while Poisoned in this way.', 250.00, NULL, FALSE),
    ('Manacles', 'As a Utilize action, you can use Manacles to bind an unwilling Small or Medium creature within 5 feet of yourself that has the Grappled, Incapacitated, or Restrained condition if you succeed on a DC 13 Dexterity (Sleight of Hand) check. While bound, a creature has Disadvantage on attack rolls, and the creature is Restrained if the Manacles are attached to a chain or hook that is fixed in place. Escaping the Manacles requires a successful DC 20 Dexterity (Sleight of Hand) check as an action. Bursting them requires a successful DC 25 Strength (Athletics) check as an action. Each set of Manacl...', 2.00, 6.00, FALSE),
    ('Map', 'If you consult an accurate Map, you gain a +5 bonus to Wisdom (Survival) checks you make to find your way in the place represented on it.', 1.00, NULL, FALSE),
    ('Map or Scroll Case', 'A Map or Scroll Case holds up to 10 sheets of paper or 5 sheets of parchment.', 1.00, 1.00, FALSE),
    ('Mastiff', 'Mount', 25.00, NULL, FALSE),
    ('Midnight Tears', 'A creature that ingests Midnight Tears suffers no effect until the stroke of midnight. Any effect that ends the Poisoned condition neutralizes this poison. If the poison hasn''t been neutralized before midnight, the creature makes a DC 17 Constitution saving throw, taking 31 (9d6) Poison damage on a failed save or half as much damage on a successful one.', 1.50, NULL, FALSE),
    ('Military Saddle', 'A saddle comes with a bit, a bridle, reins, and any other equipment needed to use the saddle. A Military Saddle gives Advantage on any ability check you make to remain mounted.', 20.00, 30.00, FALSE),
    ('Mirror', 'A handheld steel Mirror is useful for personal cosmetics but also for peeking around corners and reflecting light as a signal.', 5.00, NULL, FALSE),
    ('Mule', 'Mount', 8.00, NULL, FALSE),
    ('Musical Instrument', 'If you have proficiency with a tool, add your Proficiency Bonus to any ability check you make that uses the tool. If you have proficiency in a skill that''s used with that check, you have Advantage on the check too.', NULL, NULL, FALSE),
    ('Needle', 'Blowgun needles are used with a weapon that has the ammunition property to make a ranged attack. Each time you attack with the weapon, you expend one piece of ammunition. Drawing the ammunition from a quiver, case, or other container is part of the attack (you need a free hand to load a one-handed weapon). At the end of the battle, you can recover half your expended ammunition by taking a minute to search the battlefield. Needles are typically stored in a Pouch (bought separately).', NULL, 0.32, FALSE),
    ('Needles (50)', 'Blowgun needles are used with a weapon that has the ammunition property to make a ranged attack. Each time you attack with the weapon, you expend one piece of ammunition. Drawing the ammunition from a quiver, case, or other container is part of the attack (you need a free hand to load a one-handed weapon). At the end of the battle, you can recover half your expended ammunition by taking a minute to search the battlefield. Needles are typically stored in a Pouch (bought separately).', 1.00, 1.00, FALSE),
    ('Net', 'When you take the Attack action, you can replace one of your attacks with throwing a Net. Target a creature you can see within 15 feet of yourself. The target must succeed on a Dexterity saving throw (DC 8 plus your Dexterity modifier and Proficiency Bonus) or have the Restrained condition until it escapes. The target succeeds automatically if it is Huge or larger. To escape, the target or a creature within 5 feet of it must take an action to make a DC 10 Strength (Athletics) check, freeing the Restrained creature on a success. Destroying the Net (AC 10; 5 HP; Immunity to Bludgeoning, Poiso...', 1.00, 3.00, FALSE),
    ('Oil', 'You can douse a creature, object, or space with Oil or use it as fuel, as detailed below. When you take the Attack action, you can replace one of your attacks with throwing an Oil flask. Target one creature or object within 20 feet of yourself. The target must succeed on a Dexterity saving throw (DC 8 plus your Dexterity modifier and Proficiency Bonus) or be covered in oil. If the target takes Fire damage before the oil dries (after 1 minute), the target takes an extra 5 Fire damage from burning oil.', NULL, 1.00, FALSE),
    ('Oil of Taggit', 'A creature subjected to Oil of Taggit must succeed on a DC 13 Constitution saving throw or have the Poisoned condition for 24 hours. The creature also has the Unconscious condition while Poisoned in this way. It wakes up if it takes damage.', 400.00, NULL, FALSE),
    ('Orb', 'A sorcerer, warlock, or wizard can use this item as a spellcasting focus.', 20.00, 3.00, FALSE),
    ('Ox', 'Merchants commonly exchange trade goods without using currency.', 15.00, NULL, FALSE),
    ('Pale Tincture', 'A creature subjected to Pale Tincture must succeed on a DC 16 Constitution saving throw or take 3 (1d6) Poison damage and have the Poisoned condition. The Poisoned creature repeats the save every 24 hours, taking 3 (1d6) Poison damage on a failed save. The damage the poison deals can''t be healed by any means while the creature remains Poisoned. After seven successful saves against the poison, the creature is no longer Poisoned.', 250.00, NULL, FALSE),
    ('Paper', 'One sheet of Paper can hold about 250 handwritten words.', NULL, NULL, FALSE),
    ('Parchment', 'One sheet of Parchment can hold about 250 handwritten words.', NULL, NULL, FALSE),
    ('Pepper', 'Merchants commonly exchange trade goods without using currency.', 2.00, 1.00, FALSE),
    ('Perfume', 'Perfume comes in a 4-ounce vial. For 1 hour after applying Perfume to yourself, you have Advantage on Charisma (Persuasion) checks made to influence an Indifferent Humanoid within 5 feet of yourself.', 5.00, NULL, FALSE),
    ('Pig', 'Merchants commonly exchange trade goods without using currency.', 3.00, NULL, FALSE),
    ('Platinum', 'Merchants commonly exchange trade goods without using currency.', 500.00, 1.00, FALSE),
    ('Playing Cards', 'If you have proficiency with a tool, add your Proficiency Bonus to any ability check you make that uses the tool. If you have proficiency in a skill that''s used with that check, you have Advantage on the check too.', NULL, NULL, FALSE),
    ('Pole', 'A Pole is 10 feet long. You can use it to touch something up to 10 feet away. If you must make a Strength (Athletics) check as part of a High or Long Jump, you can use the Pole to vault, giving yourself Advantage on the check.', NULL, 7.00, FALSE),
    ('Pony', 'Mount', 30.00, NULL, FALSE),
    ('Portable Ram', 'You can use a Portable Ram to break down doors. When doing so, you gain a +4 bonus to the Strength check. One other character can help you use the ram, giving you Advantage on this check.', 4.00, 35.00, FALSE),
    ('Pouch', 'A Pouch holds up to 6 pounds within one-fifth of a cubic foot.', NULL, 1.00, FALSE),
    ('Priest''s Pack', 'A Priest''s Pack contains the following items: Backpack, Blanket, Holy Water, Lamp, 7 days of Rations, Robe, and Tinderbox.', 33.00, 29.00, FALSE),
    ('Psychic Blade', 'When making an attack with a Finesse weapon, use your choice of your Strength or Dexterity modifier for the attack and damage rolls. You must use the same modifier for both rolls. If a weapon has the Thrown property, you can throw the weapon to make a ranged attack, and you can draw that weapon as part of the attack. If the weapon is a Melee weapon, use the same ability modifier for the attack and damage rolls that you use for a melee attack with that weapon.', NULL, NULL, FALSE),
    ('Purple Worm Poison', 'A creature subjected to Purple Worm Poison makes a DC 21 Constitution saving throw, taking 35 (10d6) Poison damage on a failed save or half as much damage on a successful one.', 2.00, NULL, FALSE),
